import { useEffect, useState } from "react";

export const Age = () => {
  const [age, setAge] = useState("Loading...");
  useEffect(() => {
    fetch("http://worldtimeapi.org/api/timezone/CET")
      .then((response) => response.json())
      .then((data) => setAge(getYearsOfAge(data.datetime)));
  }, []);

  return <span>{age}</span>;
};

const getYearsOfAge = (currentDate: any): string => {
  const dateTo = new Date(currentDate);
  const dateFrom = new Date("1979-08-14");
  const months =
    dateTo.getMonth() -
    dateFrom.getMonth() +
    12 * (dateTo.getFullYear() - dateFrom.getFullYear());
  return ((months - (months % 12)) / 12).toString();
};
